using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedDatabase(SchoolContext context)
        {
            var departments = new List<Department>
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 200000, StartDate = DateTime.Parse("2007-09-01") }
            };

            var instructors = new List<Instructor>
            {
                new Instructor { ID = 1, LastName = "Abercrombie", FirstMidName = "Kim", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 2, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 3, LastName = "Harui", FirstMidName = "Roger", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() }
            };

            var courses = new List<Course>
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() }
            };

            var students = new List<Student>
            {
                new Student { ID = 10, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 11, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01"), Enrollments = new List<Enrollment>() },
                new Student { ID = 12, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2013-09-01"), Enrollments = new List<Enrollment>() }
            };

            var enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 1050, Grade = Grade.B }
            };

            context.Instructors.AddRange(instructors);
            context.Departments.AddRange(departments);
            context.Courses.AddRange(courses);
            context.Students.AddRange(students);
            context.Enrollments.AddRange(enrollments);

            // Add course assignments
            context.CourseAssignments.AddRange(new[]
            {
                new CourseAssignment { InstructorID = 1, CourseID = 1050 },
                new CourseAssignment { InstructorID = 2, CourseID = 4022 },
                new CourseAssignment { InstructorID = 1, CourseID = 4041 }
            });

            context.SaveChanges();
        }
    }
}

