using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
            {
                try { Directory.Delete(_tempPath, true); } catch { }
            }
        }

        // Index tests

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        // Details tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // Create GET tests

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // Create POST tests

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Another Course",
                Credits = 3,
                DepartmentID = 2
            };

            _controller.Create(course, null);

            Assert.Equal(4, _context.Courses.Count());
            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1111, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(course, result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_ValidImage_SetsImagePath()
        {
            var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.png", 1024);

            _controller.Create(course, mockFile.Object);

            var saved = _context.Courses.Find(7777);
            Assert.NotNull(saved);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        // Edit GET tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // Edit POST tests

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var mockFile = CreateMockFile("malware.txt", 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var mockFile = CreateMockFile("large.jpg", 6 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_ValidImage_UpdatesImagePath()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var mockFile = CreateMockFile("new_image.jpg", 2048);

            _controller.Edit(course, mockFile.Object);

            var updated = _context.Courses.Find(1050);
            Assert.NotNull(updated.TeachingMaterialImagePath);
            Assert.Contains("new_image", updated.TeachingMaterialImagePath).Equals(false);
            Assert.StartsWith("/Uploads/TeachingMaterials/", updated.TeachingMaterialImagePath);
        }

        // Delete tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseFromDatabase()
        {
            _controller.DeleteConfirmed(4041);

            Assert.Equal(2, _context.Courses.Count());
            Assert.Null(_context.Courses.Find(4041));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(4041) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        // Helper methods

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            var stream = new MemoryStream(new byte[Math.Min(length, 1024)]);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return mockFile;
        }
    }
}

