using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // Index tests

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        // Details tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
        }

        // Create GET tests

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Create POST tests

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 1
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_AddsToDatabase()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000,
                StartDate = DateTime.Parse("2023-09-01"),
                InstructorID = 2
            };

            _controller.Create(department);

            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Edit GET tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", model.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Edit POST tests

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = _context.Departments.AsNoTracking().First(d => d.DepartmentID == 1);
            department.Name = "Updated English";

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1, StartDate = DateTime.Now };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Delete GET tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(2) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Mathematics", model.Name);
        }

        // Delete POST tests

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentFromDatabase()
        {
            _controller.DeleteConfirmed(3);

            Assert.Equal(2, _context.Departments.Count());
            Assert.Null(_context.Departments.Find(3));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(3) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }
    }
}

