using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            // Drain any pre-existing notifications
            while (_controller.notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithNoItems()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
        }

        [Fact]
        public void GetNotifications_WithMessages_ReturnsNotifications()
        {
            _controller.notificationService.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            _controller.notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            for (int i = 0; i < 15; i++)
            {
                _controller.notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }
    }
}

