using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        // Person / FullName tests

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane" };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }

        // Student model tests

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
