using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void Context_CanCreateAndRetrieveStudents()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Students.Add(new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Students);
            Assert.Equal("Test", context.Students.First().LastName);
        }

        [Fact]
        public void Context_CanCreateAndRetrieveInstructors()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Instructors.Add(new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            });
            context.SaveChanges();

            Assert.Single(context.Instructors);
            Assert.Equal("Prof", context.Instructors.First().LastName);
        }

        [Fact]
        public void Context_CanCreateAndRetrieveCourses()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Courses.Add(new Course
            {
                CourseID = 5555,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 0
            });
            context.SaveChanges();

            Assert.Single(context.Courses);
            Assert.Equal("Test Course", context.Courses.First().Title);
        }

        [Fact]
        public void Context_CanCreateAndRetrieveDepartments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department
            {
                Name = "Test Department",
                Budget = 100000,
                StartDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            Assert.Single(context.Departments);
            Assert.Equal("Test Department", context.Departments.First().Name);
        }

        [Fact]
        public void Context_CanCreateEnrollments()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Enrolled",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Now
            };
            context.Students.Add(student);
            context.Courses.Add(new Course { CourseID = 100, Title = "Course", Credits = 3 });
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = 100,
                Grade = Grade.A
            });
            context.SaveChanges();

            Assert.Single(context.Enrollments);
            Assert.Equal(Grade.A, context.Enrollments.First().Grade);
        }

        [Fact]
        public void Context_CourseAssignment_CompositeKey()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(context);

            var assignment = context.CourseAssignments.Find(1050, 1);
            Assert.NotNull(assignment);
            Assert.Equal(1050, assignment.CourseID);
            Assert.Equal(1, assignment.InstructorID);
        }

        [Fact]
        public void Context_CanCreateNotifications()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Notifications.Add(new Notification
            {
                EntityType = "Test",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            });
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }

        [Fact]
        public void Context_StudentInheritsPerson()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "PersonTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Now
            };
            context.Students.Add(student);
            context.SaveChanges();

            var person = context.People.First();
            Assert.Equal("PersonTest", person.LastName);
            Assert.IsType<Student>(person);
        }

        [Fact]
        public void Context_InstructorInheritsPerson()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "PersonTest",
                FirstMidName = "Instructor",
                HireDate = DateTime.Now,
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var person = context.People.First();
            Assert.Equal("PersonTest", person.LastName);
            Assert.IsType<Instructor>(person);
        }

        [Fact]
        public void Context_OfficeAssignment_LinkedToInstructor()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room A1" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var saved = context.Instructors.Include(i => i.OfficeAssignment).First();
            Assert.NotNull(saved.OfficeAssignment);
            Assert.Equal("Room A1", saved.OfficeAssignment.Location);
        }
    }
}

